import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import { apiClient } from '@/lib/api';

export interface User {
  id: number;
  email: string;
  full_name: string;
  created_at: string;
}

export interface AuthState {
  user: User | null;
  accessToken: string | null;
  isLoading: boolean;
  error: string | null;

  // Actions
  login: (email: string, password: string) => Promise<void>;
  register: (email: string, password: string, fullName: string) => Promise<void>;
  logout: () => void;
  clearError: () => void;
  setUser: (user: User | null) => void;
  setAccessToken: (token: string | null) => void;
}

/**
 * Zustand store for authentication state management.
 * 
 * Persists auth data to localStorage automatically.
 * Handles login, registration, logout, and token management.
 */
export const authStore = create<AuthState>()(
  persist(
    (set, get) => ({
      user: null,
      accessToken: null,
      isLoading: false,
      error: null,

      login: async (email: string, password: string) => {
        set({ isLoading: true, error: null });
        try {
          const response = await apiClient.post('/auth/login', {
            email,
            password,
          });

          const { access_token, user } = response.data;

          set({
            user,
            accessToken: access_token,
            isLoading: false,
            error: null,
          });
        } catch (err: any) {
          const errorMessage =
            err.response?.data?.detail || 'Login failed. Please try again.';
          set({
            isLoading: false,
            error: errorMessage,
            user: null,
            accessToken: null,
          });
          throw err;
        }
      },

      register: async (email: string, password: string, fullName: string) => {
        set({ isLoading: true, error: null });
        try {
          const response = await apiClient.post('/auth/register', {
            email,
            password,
            full_name: fullName,
          });

          const { access_token, user } = response.data;

          set({
            user,
            accessToken: access_token,
            isLoading: false,
            error: null,
          });
        } catch (err: any) {
          const errorMessage =
            err.response?.data?.detail || 'Registration failed. Please try again.';
          set({
            isLoading: false,
            error: errorMessage,
            user: null,
            accessToken: null,
          });
          throw err;
        }
      },

      logout: () => {
        set({
          user: null,
          accessToken: null,
          isLoading: false,
          error: null,
        });
      },

      clearError: () => {
        set({ error: null });
      },

      setUser: (user: User | null) => {
        set({ user });
      },

      setAccessToken: (token: string | null) => {
        set({ accessToken: token });
      },
    }),
    {
      name: 'auth-store',
      partialize: (state) => ({
        user: state.user,
        accessToken: state.accessToken,
      }),
    }
  )
);

/**
 * Custom hook wrapper for auth store
 */
export const useAuth = () => {
  return authStore();
};

/**
 * Check if user is authenticated
 */
export const isAuthenticated = (): boolean => {
  const state = authStore.getState();
  return !!state.user && !!state.accessToken;
};

/**
 * Get current user
 */
export const getCurrentUser = (): User | null => {
  return authStore.getState().user;
};

/**
 * Get access token
 */
export const getAccessToken = (): string | null => {
  return authStore.getState().accessToken;
};

import React, { useMemo } from 'react';
import { useQuery } from '@tanstack/react-query';
import { BarChart3, Briefcase, FileText, TrendingUp } from 'lucide-react';
import { apiClient } from '@/lib/api';
import { authStore } from '@/stores/auth.store';
import LoadingSpinner from '@/components/common/LoadingSpinner';
import ErrorAlert from '@/components/common/ErrorAlert';
import StatCard from '@/components/dashboard/StatCard';
import JobListingsPreview from '@/components/dashboard/JobListingsPreview';
import PlatformStatus from '@/components/dashboard/PlatformStatus';

interface DashboardStats {
  total_jobs_saved: number;
  total_applications: number;
  pending_applications: number;
  profile_completion: number;
}

interface RecentJob {
  id: number;
  title: string;
  company: string;
  location: string;
  salary_range: string | null;
  posted_date: string;
}

interface DashboardData {
  stats: DashboardStats;
  recent_jobs: RecentJob[];
}

/**
 * DashboardPage: Main dashboard component
 * 
 * Displays:
 * - Job statistics cards (saved, applications, pending)
 * - Profile completion progress
 * - Recent job listings preview
 * - Platform connection status
 * 
 * Uses React Query for server state management with caching.
 */
const DashboardPage: React.FC = () => {
  const user = authStore((state) => state.user);

  /**
   * Fetch dashboard data (stats + recent jobs)
   * Cache for 5 minutes, refetch on window focus
   */
  const {
    data: dashboardData,
    isLoading,
    isError,
    error,
    refetch,
  } = useQuery<DashboardData>({
    queryKey: ['dashboard', user?.id],
    queryFn: async () => {
      const response = await apiClient.get<DashboardData>('/dashboard');
      return response.data;
    },
    staleTime: 5 * 60 * 1000,
    gcTime: 10 * 60 * 1000,
    retry: 1,
    enabled: !!user,
  });

  /**
   * Prepare stats for display with icons and colors
   */
  const statCards = useMemo(() => {
    if (!dashboardData) return [];

    return [
      {
        title: 'Jobs Saved',
        value: dashboardData.stats.total_jobs_saved,
        icon: Briefcase,
        color: 'bg-blue-50',
        textColor: 'text-blue-700',
        trend: '+12% this month',
      },
      {
        title: 'Applications',
        value: dashboardData.stats.total_applications,
        icon: FileText,
        color: 'bg-green-50',
        textColor: 'text-green-700',
        trend: `${dashboardData.stats.pending_applications} pending`,
      },
      {
        title: 'Profile Strength',
        value: `${dashboardData.stats.profile_completion}%`,
        icon: TrendingUp,
        color: 'bg-purple-50',
        textColor: 'text-purple-700',
        trend: 'Complete your profile',
      },
      {
        title: 'Opportunities',
        value: dashboardData.recent_jobs.length,
        icon: BarChart3,
        color: 'bg-orange-50',
        textColor: 'text-orange-700',
        trend: 'This week',
      },
    ];
  }, [dashboardData]);

  /**
   * Handle error with retry capability
   */
  if (isError) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-slate-50 to-slate-100 p-6">
        <div className="max-w-7xl mx-auto">
          <ErrorAlert
            title="Failed to load dashboard"
            message={
              error instanceof Error
                ? error.message
                : 'An error occurred while fetching dashboard data'
            }
            onRetry={refetch}
          />
        </div>
      </div>
    );
  }

  /**
   * Show loading state
   */
  if (isLoading) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-slate-50 to-slate-100 flex items-center justify-center p-6">
        <LoadingSpinner message="Loading your dashboard..." />
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-50 to-slate-100">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 shadow-sm">
        <div className="max-w-7xl mx-auto px-6 py-8">
          <div className="flex items-center justify-between">
            <div>
              <h1 className="text-3xl font-bold text-slate-900">
                Welcome back, {user?.full_name || 'User'}
              </h1>
              <p className="text-slate-600 mt-2">
                Here's your job search overview for today
              </p>
            </div>
            <button
              onClick={() => refetch()}
              className="px-4 py-2 bg-primary-600 text-white rounded-lg hover:bg-primary-700 transition-colors font-medium"
            >
              Refresh
            </button>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-7xl mx-auto px-6 py-8">
        {/* Statistics Grid */}
        <section className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
          {statCards.map((card) => (
            <StatCard
              key={card.title}
              title={card.title}
              value={card.value}
              icon={card.icon}
              color={card.color}
              textColor={card.textColor}
              trend={card.trend}
            />
          ))}
        </section>

        {/* Content Grid */}
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          {/* Recent Job Listings - spans 2 cols */}
          <div className="lg:col-span-2">
            <JobListingsPreview
              jobs={dashboardData?.recent_jobs || []}
              isLoading={isLoading}
            />
          </div>

          {/* Platform Status - spans 1 col */}
          <div>
            <PlatformStatus />
          </div>
        </div>

        {/* Quick Actions Section */}
        <section className="mt-8 bg-white rounded-lg shadow-sm border border-slate-200 p-6">
