export default function JobsPage(): React.ReactElement {
  const [currentPage, setCurrentPage] = useState(1);
  const [pageSize, setPageSize] = useState(12);
  const [filters, setFilters] = useState<FilterState>(INITIAL_FILTERS);
  const [showFilters, setShowFilters] = useState(false);
  const { user } = authStore();

  const pageSize_param = pageSize;

  // Build query params
  const queryParams = useMemo(() => {
    const params: Record<string, string | number> = {
      page: currentPage,
      page_size: pageSize_param,
    };

    if (filters.search) params.search = filters.search;
    if (filters.location) params.location = filters.location;
    if (filters.category) params.category = filters.category;
    if (filters.jobType) params.job_type = filters.jobType;
    if (filters.minSalary) params.min_salary = filters.minSalary;
    if (filters.skills.length > 0) params.skills = filters.skills.join(',');

    return params;
  }, [currentPage, pageSize_param, filters]);

  // Fetch jobs
  const {
    data: jobsData,
    isLoading,
    error,
    refetch,
  } = useQuery<JobsResponse>({
    queryKey: ['jobs', queryParams],
    queryFn: async () => {
      const response = await apiClient.get<JobsResponse>('/jobs', {
        params: queryParams,
      });
      return response.data;
    },
    staleTime: 5 * 60 * 1000, // 5 minutes
    enabled: !!user, // Only fetch if user is logged in
  });

  const handleFilterChange = (key: keyof FilterState, value: unknown) => {
    setFilters((prev) => ({
      ...prev,
      [key]: value,
    }));
    setCurrentPage(1); // Reset to first page on filter change
  };

  const handleResetFilters = () => {
    setFilters(INITIAL_FILTERS);
    setCurrentPage(1);
  };

  const handleSaveJob = async (jobId: number) => {
    try {
      await apiClient.post(`/jobs/${jobId}/save`);
      await refetch();
