      console.error('Failed to save job:', err);
    }
  };

  const handleShareJob = (job: Job) => {
    const shareText = `Check out this job: ${job.title} at ${job.company}`;
    if (navigator.share) {
      navigator.share({
        title: job.title,
        text: shareText,
      });
    } else {
      // Fallback: copy to clipboard
      navigator.clipboard.writeText(
