      Contract: 'bg-purple-100 text-purple-800',
      Remote: 'bg-indigo-100 text-indigo-800',
      Internship: 'bg-yellow-100 text-yellow-800',
    };
    return typeColorMap[jobType] || 'bg-gray-100 text-gray-800';
  };

  if (!user) {
