  const [showCoverLetterModal, setShowCoverLetterModal] = useState(false);
  const [showApplicationSuccess, setShowApplicationSuccess] = useState(false);

  if (!jobId || !user) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50">
        <ErrorAlert message="Invalid job ID or user not authenticated" />
      </div>
    );
  }

  // Fetch job details
  const {
    data: job,
    isLoading: jobLoading,
    error: jobError,
  } = useQuery<Job>({
    queryKey: ['job', jobId],
    queryFn: () => apiClient.get(`/jobs/${jobId}`).then((res) => res.data),
    staleTime: 1000 * 60 * 5, // 5 minutes
  });

  // Generate cover letter mutation
  const generateCoverLetterMutation = useMutation({
    mutationFn: async (jobIdStr: string) => {
      const response = await apiClient.post<CoverLetterGenerationResponse>(
        '/ai/generate-cover-letter',
        { job_id: parseInt(jobIdStr) }
      );
      return response.data;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['coverLetter', jobId] });
    },
  });

  // Fetch existing cover letter
  const {
