      try {
        const response = await apiClient.get<CoverLetterGenerationResponse>(
          `/ai/cover-letter/${jobId}`
        );
        return response.data;
      } catch (error: any) {
        if (error.response?.status === 404) {
          return null;
        }
        throw error;
      }
    },
    enabled: !!jobId,
