import ErrorAlert from '@/components/common/ErrorAlert';
import SuccessAlert from '@/components/common/SuccessAlert';
import clsx from 'clsx';

interface Resume {
  id: number;
  user_id: number;
  original_content: string;
  optimized_content: string | null;
  file_name: string;
  created_at: string;
  updated_at: string;
}

interface OptimizationResult {
  resume_id: number;
  optimized_content: string;
  improvements: string[];
  ats_score: number;
}

/**
 * ResumePage: Upload, view, and optimize resumes with AI assistance.
 * Features:
 * - File upload (PDF, DOCX, TXT)
 * - Resume preview
 * - AI optimization with before/after diff
 * - Download optimized resume
 * - ATS score display
 */
const ResumePage: React.FC = () => {
  const queryClient = useQueryClient();
  const user = authStore((state) => state.user);
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [showDiff, setShowDiff] = useState(false);
  const [optimizationExpandedId, setOptimizationExpandedId] = useState<number | null>(null);

  // Fetch user's resumes
  const {
    data: resumes = [],
    isLoading: isLoadingResumes,
    error: resumesError,
  } = useQuery({
    queryKey: ['resumes'],
    queryFn: async () => {
      if (!user?.id) return [];
      const response = await apiClient.get(`/resumes`, {
        params: { user_id: user.id },
      });
      return response.data.data || [];
    },
    enabled: !!user?.id,
  });

  // Upload resume mutation
  const uploadMutation = useMutation({
    mutationFn: async (file: File) => {
      const formData = new FormData();
      formData.append('file', file);

      const response = await apiClient.post('/resumes/upload', formData, {
        headers: {
          'Content-Type': 'multipart/form-data',
        },
      });
      return response.data.data;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['resumes'] });
      setSelectedFile(null);
      setShowDiff(false);
    },
  });

  // Optimize resume mutation
  const optimizeMutation = useMutation({
    mutationFn: async (resumeId: number) => {
      const response = await apiClient.post(`/resumes/${resumeId}/optimize`, {});
      return response.data.data;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['resumes'] });
    },
  });

  // Delete resume mutation
  const deleteMutation = useMutation({
    mutationFn: async (resumeId: number) => {
      await apiClient.delete(`/resumes/${resumeId}`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['resumes'] });
    },
  });

  // Handle file selection
  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files?.[0]) {
      const file = e.target.files[0];
      const validTypes = ['application/pdf', 'application/vnd.openxmlformats-officedocument.wordprocessingml.document', 'text/plain'];

      if (!validTypes.includes(file.type)) {
        alert('Please upload a PDF, DOCX, or TXT file');
        return;
      }

      if (file.size > 5 * 1024 * 1024) {
        alert('File size must be less than 5MB');
        return;
      }

      setSelectedFile(file);
    }
  };

  // Handle upload
  const handleUpload = async () => {
    if (!selectedFile) return;
    await uploadMutation.mutateAsync(selectedFile);
  };

  // Handle optimize
  const handleOptimize = async (resumeId: number) => {
    await optimizeMutation.mutateAsync(resumeId);
  };

  // Handle delete
  const handleDelete = async (resumeId: number) => {
    if (window.confirm('Are you sure you want to delete this resume?')) {
      await deleteMutation.mutateAsync(resumeId);
    }
  };

  // Download resume as text
  const handleDownload = (content: string, fileName: string) => {
    const element = document.createElement('a');
    element.setAttribute('href', `data:text/plain;charset=utf-8,${encodeURIComponent(content)}`);
    element.setAttribute('download', fileName.replace(/\.[^/.]+$/, '_optimized.txt'));
    element.style.display = 'none';
    document.body.appendChild(element);
    element.click();
    document.body.removeChild(element);
  };

  if (!user) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <ErrorAlert message="Please log in to access resume management" />
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-50 to-slate-100 py-8 px-4">
      <div className="max-w-6xl mx-auto">
        {/* Header */}
        <div className="mb-8">
          <div className="flex items-center gap-3 mb-2">
            <FileText className="w-8 h-8 text-primary-600" />
            <h1 className="text-3xl font-bold text-slate-900">Resume Management</h1>
          </div>
          <p className="text-slate-600">Upload, optimize, and manage your resumes with AI assistance</p>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Upload Section */}
          <div className="lg:col-span-1">
            <div className="bg-white rounded-lg shadow-sm p-6 border border-slate-200 sticky top-24">
              <h2 className="text-lg font-semibold text-slate-900 mb-4">Upload Resume</h2>

              {/* File Input */}
              <div className="mb-4">
                <label
                  htmlFor="resume-upload"
                  className={clsx(
                    'block w-full p-6 border-2 border-dashed rounded-lg text-center cursor-pointer transition-colors',
                    selectedFile
                      ? 'border-primary-500 bg-primary-50'
                      : 'border-slate-300 bg-slate-50 hover:border-primary-400 hover:bg-primary-50'
                  )}
                >
                  <div className="flex flex-col items-center gap-2">
                    <Upload className="w-8 h-8 text-primary-600" />
                    <span className="text-sm font-medium text-slate-700">
                      {selectedFile ? selectedFile.name : 'Click to upload or drag'}
                    </span>
                    <span className="text-xs text-slate-500">PDF, DOCX, or TXT • Max 5MB</span>
                  </div>
                  <input
                    id="resume-upload"
                    type="file"
                    accept=".pdf,.docx,.txt"
                    onChange={handleFileSelect}
                    className="hidden"
                  />
                </label>
              </div>

              {/* Upload Button */}
              <button
                onClick={handleUpload}
                disabled={!selectedFile || uploadMutation.isPending}
                className={clsx(
                  'w-full py-2 px-4 rounded-lg font-medium transition-colors flex items-center justify-center gap-2',
                  selectedFile && !uploadMutation.isPending
                    ? 'bg-primary-600 text-white hover:bg-primary-700'
                    : 'bg-slate-100 text-slate-400 cursor-not-allowed'
                )}
              >
                {uploadMutation.isPending ? (
                  <>
                    <Loader className="w-4 h-4 animate-spin" />
                    Uploading...
                  </>
                ) : (
                  <>
                    <Upload className="w-4 h-4" />
                    Upload Resume
                  </>
                )}
              </button>

              {uploadMutation.error && (
                <ErrorAlert message={(uploadMutation.error as Error).message} className="mt-4" />
              )}

              {uploadMutation.isSuccess && (
                <SuccessAlert message="Resume uploaded successfully!" className="mt-4" />
              )}

              {/* Info Box */}
              <div className="mt-6 p-4 bg-primary-50 rounded-lg border border-primary-200">
                <div className="flex gap-3">
                  <AlertCircle className="w-5 h-5 text-primary-600 flex-shrink-0 mt-0.5" />
                  <div className="text-sm text-primary-900">
                    <p className="font-medium mb-1">AI Optimization Tips:</p>
                    <ul className="list-disc list-inside space-y-1 text-primary-800">
                      <li>Include measurable achievements</li>
                      <li>Use industry keywords</li>
                      <li>Tailor to job descriptions</li>
                      <li>Keep formatting clean</li>
                    </ul>
                  </div>
                </div>
              </div>
            </div>
          </div>

          {/* Resumes List Section */}
          <div className="lg:col-span-2">
            {isLoadingResumes ? (
              <LoadingSpinner />
            ) : resumesError ? (
              <ErrorAlert message="Failed to load resumes" />
            ) : resumes.length === 0 ? (
              <div className="bg-white rounded-lg shadow-sm p-12 border border-slate-200 text-center">
                <FileText className="w-12 h-12 text-slate-300 mx-auto mb-4" />
                <h3 className="text-lg font-medium text-slate-900 mb-2">No resumes yet</h3>
                <p className="text-slate-600">Upload your first resume to get started</p>
              </div>
            ) : (
              <div className="space-y-4">
                {resumes.map((resume: Resume) => (
                  <div key={resume.id} className="bg-white rounded-lg shadow-sm border border-slate-200 overflow-hidden">
                    {/* Resume Header */}
                    <div className="p-6 border-b border-slate-200">
                      <div className="flex items-start justify-between mb-3">
                        <div className="flex-1">
                          <h3 className="text-lg font-semibold text-slate-900">{resume.file_name}</h3>
                          <p className="text-sm text-slate-500 mt-1">
                            Created {new Date(resume.created_at).toLocaleDateString()}
                          </p>
                        </div>
                        <div className="flex gap-2">
                          <button
                            onClick={() => setOptimizationExpandedId(
                              optimizationExpandedId === resume.id ? null : resume.id
                            )}
                            className="p-2 hover:bg-slate-100 rounded-lg transition-colors"
                            title="View details"
                          >
                            <Eye className="w-5 h-5 text-slate-600" />
                          </button>
                          <button
                            onClick={() => handleDelete(resume.id)}
                            disabled={deleteMutation.isPending}
                            className="p-2 hover:bg-red-50 rounded-lg transition-colors disabled:opacity-50"
                            title="Delete resume"
                          >
                            <AlertCircle className="w-5 h-5 text-red-500" />
                          </button>
                        </div>
                      </div>

                      {/* Status Badge */}
                      <div className="flex items-center gap-3">
                        {resume.optimized_content ? (
                          <span className="inline-flex items-center gap-1 px-3 py-1 bg-green-100 text-green-800 text-xs font-medium rounded-full">
                            <CheckCircle2 className="w-3 h-3" />
                            Optimized
                          </span>
                        ) : (
                          <span className="inline-flex items-center gap-1 px-3 py-1 bg-yellow-100 text-yellow-800 text-xs font-medium rounded-full">
                            <AlertCircle className="w-3 h-3" />
                            Original
                          </span>
                        )}
                      </div>
                    </div>

                    {/* Expandable Details */}
                    {optimizationExpandedId === resume.id && (
                      <div className="p-6 space-y-6">
                        {/* Original Content */}
                        <div>
                          <h4 className="font-semibold text-slate-900 mb-3">Original Resume</h4>
                          <div className="bg-slate-50 rounded-lg p-4 h-48 overflow-y-auto border border-slate-200">
                            <p className="text-sm text-slate-700 whitespace-pre-wrap font-mono">
                              {resume.original_content.substring(0, 500)}...
                            </p>
                          </div>
                        </div>

                        {/* Optimize Button or Optimized Content */}
                        {!resume.optimized_content ? (
                          <button
                            onClick={() => handleOptimize(resume.id)}
                            disabled={optimizeMutation.isPending}
                            className="w-full py-3 px-4 bg-primary-600 text-white font-medium rounded-lg hover:bg-primary-700 transition-colors flex items-center justify-center gap-2 disabled:opacity-50"
                          >
                            {optimizeMutation.isPending ? (
                              <>
                                <Loader className="w-4 h-4 animate-spin" />
                                Optimizing...
                              </>
                            ) : (
                              <>
                                <Zap className="w-4 h-4" />
                                AI Optimize Resume
                              </>
                            )}
                          </button>
                        ) : (
                          <>
                            <div className="grid grid-cols-2 gap-4">
                              <div>
                                <h4 className="font-semibold text-slate-900 mb-3">Optimized Resume</h4>
                                <div className="bg-green-50 rounded-lg p-4 h-48 overflow-y-auto border border-green-200

import React, { useState } from 'react';
import { Outlet, useLocation } from 'react-router-dom';
import { Menu, X, LogOut, Settings } from 'lucide-react';
import { authStore } from '@/stores/auth.store';
import Sidebar from '@/components/layout/Sidebar';
import clsx from 'clsx';

const AppLayout: React.FC = () => {
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const { pathname } = useLocation();
  const { user, logout } = authStore();

  const handleLogout = () => {
    logout();
  };

  const toggleSidebar = () => {
    setSidebarOpen(!sidebarOpen);
  };

  const closeSidebar = () => {
    setSidebarOpen(false);
  };

  return (
    <div className="flex h-screen bg-slate-900">
      {/* Mobile overlay */}
      {sidebarOpen && (
        <div
          className="fixed inset-0 z-40 bg-black bg-opacity-50 lg:hidden"
          onClick={closeSidebar}
        />
      )}

      {/* Sidebar */}
      <div
        className={clsx(
          'fixed inset-y-0 left-0 z-50 w-64 transform transition-transform duration-200 ease-in-out lg:relative lg:z-auto lg:translate-x-0',
          sidebarOpen ? 'translate-x-0' : '-translate-x-full'
        )}
      >
        <Sidebar onClose={closeSidebar} />
      </div>

      {/* Main content */}
      <div className="flex flex-1 flex-col overflow-hidden">
        {/* Header */}
        <header className="border-b border-slate-700 bg-slate-800 shadow-sm">
          <div className="flex items-center justify-between px-4 py-4 sm:px-6 lg:px-8">
            {/* Left side: menu toggle + title */}
            <div className="flex items-center gap-4">
              <button
                onClick={toggleSidebar}
                className="inline-flex items-center justify-center rounded-md p-2 text-slate-300 hover:bg-slate-700 hover:text-white lg:hidden"
                aria-label="Toggle sidebar"
              >
                {sidebarOpen ? (
                  <X className="h-6 w-6" />
                ) : (
                  <Menu className="h-6 w-6" />
                )}
              </button>
              <h1 className="text-xl font-semibold text-white">
                AI Job Assistant
              </h1>
            </div>

            {/* Right side: user menu */}
            <div className="flex items-center gap-4">
              {user && (
                <div className="flex items-center gap-3">
                  {/* User avatar */}
                  <div className="flex h-10 w-10 items-center justify-center rounded-full bg-gradient-to-br from-primary-400 to-primary-600">
                    <span className="text-sm font-semibold text-white">
                      {user.full_name
                        .split(' ')
                        .map((n) => n[0])
                        .join('')
                        .toUpperCase()}
                    </span>
                  </div>

                  {/* User info */}
                  <div className="hidden flex-col sm:flex">
                    <p className="text-sm font-medium text-white">
                      {user.full_name}
                    </p>
                    <p className="text-xs text-slate-400">{user.email}</p>
                  </div>

                  {/* Dropdown menu */}
                  <div className="relative group">
                    <button
                      className="rounded-md p-2 text-slate-300 hover:bg-slate-700 hover:text-white"
                      aria-label="User menu"
                    >
                      <svg
                        className="h-5 w-5"
                        fill="currentColor"
                        viewBox="0 0 20 20"
                      >
                        <path d="M5.293 7.293a1 1 0 011.414 0L10 10.586l3.293-3.293a1 1 0 111.414 1.414l-4 4a1 1 0 01-1.414 0l-4-4a1 1 0 010-1.414z" />
                      </svg>
                    </button>

                    {/* Dropdown content */}
                    <div className="absolute right-0 mt-0 w-48 rounded-lg border border-slate-600 bg-slate-800 py-1 shadow-lg opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all duration-150 z-10">
                      <button
                        className="flex w-full items-center gap-3 px-4 py-2 text-sm text-slate-300 hover:bg-slate-700 hover:text-white"
                        aria-label="Settings"
                      >
                        <Settings className="h-4 w-4" />
                        Settings
                      </button>
                      <button
                        onClick={handleLogout}
                        className="flex w-full items-center gap-3 px-4 py-2 text-sm text-slate-300 hover:bg-slate-700 hover:text-white border-t border-slate-600"
                        aria-label="Logout"
                      >
                        <LogOut className="h-4 w-4" />
                        Logout
                      </button>
                    </div>
                  </div>
                </div>
              )}
            </div>
          </div>
        </header>

        {/* Main content area */}
        <main className="flex-1 overflow-auto bg-slate-900">
          <div className="h-full">
            <Outlet />
          </div>
        </main>
      </div>
    </div>
  );
};

export default AppLayout;

import React, { useMemo } from 'react';
import { Heart, ExternalLink, Badge } from 'lucide-react';
import clsx from 'clsx';

interface JobCardProps {
  id: number;
  title: string;
  company: string;
  location: string;
  salary_min: number | null;
  salary_max: number | null;
  currency: string;
  skills_required: string[];
  job_type: string;
  match_score?: number;
  is_saved?: boolean;
  onViewDetails: (id: number) => void;
  onSave?: (id: number) => void;
  onUnsave?: (id: number) => void;
}

/**
 * JobCard Component
 * 
 * Reusable card component for displaying job listings.
 * Features:
 * - Company logo/avatar
 * - Job title, location, salary range
 * - Skills badges with truncation
 * - Match score indicator (if available)
 * - Save/unsave button
 * - View details action
 */
const JobCard: React.FC<JobCardProps> = ({
  id,
  title,
  company,
  location,
  salary_min,
  salary_max,
  currency,
  skills_required,
  job_type,
  match_score,
  is_saved = false,
  onViewDetails,
  onSave,
  onUnsave,
}) => {
  const displaySkills = useMemo(() => {
    return skills_required.slice(0, 3);
  }, [skills_required]);

  const remainingSkillsCount = skills_required.length - displaySkills.length;

  const getCompanyInitials = (companyName: string): string => {
    return companyName
      .split(' ')
      .map((word) => word[0])
      .join('')
      .toUpperCase()
      .slice(0, 2);
  };

  const getMatchScoreColor = (score: number): string => {
    if (score >= 80) return 'bg-green-100 text-green-800';
    if (score >= 60) return 'bg-blue-100 text-blue-800';
    if (score >= 40) return 'bg-yellow-100 text-yellow-800';
    return 'bg-red-100 text-red-800';
  };

  const formatSalary = (): string => {
    if (!salary_min && !salary_max) return 'Competitive';
    if (salary_min && salary_max) {
      return `${currency} ${salary_min.toLocaleString()} - ${salary_max.toLocaleString()}`;
    }
    const salary = salary_min || salary_max;
    return `${currency} ${salary?.toLocaleString()}`;
  };

  const handleSaveClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (is_saved && onUnsave) {
      onUnsave(id);
    } else if (!is_saved && onSave) {
      onSave(id);
    }
  };

  return (
    <div
      className={clsx(
        'border rounded-lg p-4 hover:shadow-lg transition-shadow duration-200 cursor-pointer bg-white',
        'hover:border-primary-400',
        'border-slate-200'
      )}
      onClick={() => onViewDetails(id)}
    >
      {/* Header with company and save button */}
      <div className="flex items-start justify-between gap-4 mb-3">
        <div className="flex items-start gap-3 flex-1 min-w-0">
          {/* Company Avatar */}
          <div className="flex-shrink-0 w-10 h-10 rounded-lg bg-gradient-to-br from-primary-400 to-primary-600 flex items-center justify-center text-white font-semibold text-sm">
            {getCompanyInitials(company)}
          </div>

          {/* Company and title info */}
          <div className="flex-1 min-w-0">
            <p className="text-xs font-medium text-slate-500 truncate">
              {company}
            </p>
            <h3 className="text-sm font-semibold text-slate-900 line-clamp-2 leading-tight">
              {title}
            </h3>
          </div>
        </div>

        {/* Save button */}
        <button
          onClick={handleSaveClick}
          className={clsx(
            'flex-shrink-0 p-2 rounded-lg transition-colors duration-200',
            is_saved
              ? 'bg-red-100 text-red-600 hover:bg-red-200'
              : 'bg-slate-100 text-slate-400 hover:bg-slate-200 hover:text-slate-600'
          )}
          aria-label={is_saved ? 'Unsave job' : 'Save job'}
        >
          <Heart
            size={16}
            className={is_saved ? 'fill-current' : ''}
          />
        </button>
      </div>

      {/* Location and job type */}
      <div className="flex flex-wrap items-center gap-4 text-xs text-slate-600 mb-3">
        <div className="flex items-center gap-1">
          <Badge size={14} className="text-slate-500" />
          <span>{location}</span>
        </div>
        <span className="px-2 py-1 rounded bg-slate-100 text-slate-700 font-medium">
          {job_type}
        </span>
      </div>

      {/* Salary */}
      <div className="mb-3 text-sm font-medium text-slate-900">
        {formatSalary()}
      </div>

      {/* Skills badges */}
      <div className="flex flex-wrap gap-2 mb-3">
        {displaySkills.map((skill, idx) => (
          <span
            key={idx}
            className="px-2 py-1 rounded-full bg-primary-50 text-primary-700 text-xs font-medium"
          >
            {skill}
          </span>
        ))}
        {remainingSkillsCount > 0 && (
          <span className="px-2 py-1 rounded-full bg-slate-100 text-slate-600 text-xs font-medium">
            +{remainingSkillsCount} more
          </span>
        )}
      </div>

      {/* Footer: Match score and action */}
      <div className="flex items-center justify-between pt-3 border-t border-slate-100">
        {match_score !== undefined && (
          <div
            className={clsx(
              'px-2 py-1 rounded text-xs font-semibold',
              getMatchScoreColor(match_score)
            )}
          >
            {match_score}% Match
          </div>
        )}
        <button
          onClick={() => onViewDetails(id)}
          className="flex items-center gap-1 text-primary-600 hover:text-primary-700 font-medium text-xs ml-auto"
        >
          View Details
          <ExternalLink size={14} />
        </button>
      </div>
    </div>
  );
};

export default JobCard;
